#include<iostream>#include<climits>#include<vector>#include<algorithm>#define ll long longusing namespace std; int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        ll n,m;        cin>>n>>m;        vector<vector<ll>>cols(m,vector<ll>(n));        for(int i=0;i<n;i++){            for(int j=0;j<m;j++){                ll val;                cin>>val;                cols[j][i]=val;            }        }        ll total_winning=0;        for(int j=0;j<m;j++){            sort(cols[j].begin(),cols[j].end());            for(int i=0;i<n;i++){                total_winning+=cols[j][i]*(i);                total_winning-=cols[j][i]*(n- 1 - i);            }        }        cout<<total_winning<<"\n";    } }